from collections import deque
from typing import List

def removeInvalidParentheses(s: str) -> List[str]:
    def is_valid(string: str) -> bool:
        count = 0
        for ch in string:
            if ch == '(':
                count += 1
            elif ch == ')':
                count -= 1
            if count < 0:
                return False
        return count == 0

    result: List[str] = []
    visited = {s}
    queue: deque = deque([s])
    found = False

    while queue:
        current = queue.popleft()
        if is_valid(current):
            result.append(current)
            found = True
        if found:
            continue
        for i, ch in enumerate(current):
            if ch not in ('(', ')'):
                continue
            nxt = current[:i] + current[i + 1:]
            if nxt not in visited:
                visited.add(nxt)
                queue.append(nxt)

    return result
